logger = logging.getLogger(__name__)


class Severity(str, Enum):
    """Severity levels for introspection findings."""
    P0 = "P0"  # CRITICAL - Healing blocker
    P1 = "P1"  # HIGH - Generate fix, flag for review
    P2 = "P2"  # MEDIUM - Generate fix, auto-apply if tests pass
    P3 = "P3"  # LOW - Log and schedule


class ComplexityLevel(str, Enum):
    """Complexity scoring levels."""
    LOW = "LOW"       # 1-5
    MEDIUM = "MEDIUM" # 6-10
    HIGH = "HIGH"     # 11-15
    CRITICAL = "CRITICAL"  # >15


@dataclass
class FunctionInfo:
    """Information about a single function/method."""
    id: str
    name: str
    module: str
    file_path: str
    line_number: int
    inputs: List[str] = field(default_factory=list)
    outputs: List[str] = field(default_factory=list)
    side_effects: List[str] = field(default_factory=list)
    has_tests: bool = False
    coverage_percent: float = 0.0
    complexity_score: int = 1
    complexity_level: ComplexityLevel = ComplexityLevel.LOW
    severity: Severity = Severity.P3
    has_docstring: bool = False
    has_type_annotations: bool = False
    has_error_handling: bool = False
    is_public: bool = True
    is_async: bool = False
    decorators: List[str] = field(default_factory=list)
    calls_external: List[str] = field(default_factory=list)
    bare_except_count: int = 0


@dataclass
class ModuleInfo:
    """Information about a module."""
    name: str
    file_path: str
    functions: List[str] = field(default_factory=list)
    classes: List[str] = field(default_factory=list)
    imports_internal: List[str] = field(default_factory=list)
    imports_external: List[str] = field(default_factory=list)
    has_tests: bool = False
    is_dead_code: bool = False


@dataclass
class DependencyEdge:
    """Edge in dependency graph."""
    source: str
    target: str
    dependency_type: str  # "internal" or "external"
    import_statement: str = ""


@dataclass
class DeadCodeItem:
    """Dead code item."""
    item_type: str  # "function", "class", "module", "import"
    name: str
    file_path: str
    line_number: int
    reason: str
    severity: Severity = Severity.P3
    auto_fix_available: bool = True


@dataclass
class TypeCoverageGap:
    """Type annotation gap."""
    item_type: str
    name: str
    file_path: str
    missing_annotations: List[str] = field(default_factory=list)
    has_any_type: bool = False
    severity: Severity = Severity.P2


@dataclass
class ErrorHandlingGap:
    """Error handling gap."""
    function_name: str
    file_path: str
    line_number: int
    gap_type: str  # "no_handling", "bare_except", "missing_return_validation"
    severity: Severity = Severity.P1
    recommendation: str = ""


@dataclass
class IntrospectionReport:
    """Complete introspection report."""
    timestamp: str
    project_root: str
    total_modules: int
    total_functions: int
    total_classes: int
    functions: List[FunctionInfo] = field(default_factory=list)
    modules: List[ModuleInfo] = field(default_factory=list)
